'''
Calculates the multiplication of an integer vector of size n to a matrix of size (n, m) 

RSR related implementation has been removed

'''


class MatrixMultiplier(ABC):
    def __init__(self, A=None):
        self._A = A
        self._n = 0
        self._m = 0
        if A is not None:
            self._n = len(A)  # rows count
            self._m = len(A[0])  # columns count

    @abstractmethod
    def multiply(self, v):
        pass

    @property
    def A(self):
        return self._A

    @property
    def n(self):
        return self._n

    @property
    def m(self):
        return self._m

    '''
    Dump the only necessary `data` to run the `multiply()`
    '''
    @abstractmethod
    def dump(self):
        pass

    '''
    Given the output of `dump()`, create a minimal object
    '''
    @classmethod
    def load(cls, data):
        pass


class NaiveMultiplier(MatrixMultiplier):
    def multiply(self, v):
        return np.dot(v, self.A)

    def dump(self):
        return self.A

    @classmethod
    def load(cls, data):
        return cls(A=data)
